var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"처음 만났던 순간부터 줄곧 생각해왔어.","JPN":"初めて会った瞬間からずっと思っていたわ。","ENG":"I've been thinking about it ever since we first met.","TWN":"從第一次見面起，我就一直在想。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"전대장으로 내가 선택되지 않았다면, 다 그럴만한 이유가 있을 거야.","JPN":"私が戦隊長に選ばれなかったら、それなりの理由があるはず。","ENG":"If I wasn't chosen as the next Commander, I'm sure there's a good reason.","TWN":"如果我沒有被選為戰隊長，一定是有充分理由的。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"전대장으로 그 아이가 선택되었다면, 다 그럴만한 이유가 있을 거고.","JPN":"あの子が戦隊長に選ばれたら、それなりの理由があるはずだし。","ENG":"And if she is chosen as our next Commander, I'm sure there's good reason for that too.","TWN":"如果那個孩子被選為戰隊長，也一定是有充分理由的。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그리니까 우선 그 아이를 만나보자.","JPN":"だから、まずはあの子に会ってみよう。","ENG":"So first, let's go meet her.","TWN":"所以，我們先去見見那個孩子吧。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"결정은…… 길고양이가 새로운 집을 찾은 뒤에 해도 늦지 않으니까.","JPN":"野良猫が新しい家を探した後に決めても……遅くないから。","ENG":"It won't be too late... to decide after we bring her to her new home.","TWN":"至於決定……等流浪的小貓找到新家之後再做也不遲。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"narration","speaker":null,"text":{"KOREA":"아무리 내 의지와 관계없었던 일이라고 해도.","JPN":"いくら自分の意志とは関係のないことだとしても。","ENG":"Even if this is something that is unrelated to my will.","TWN":"即使那是與我的意志無關的事情。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L11_1","type":"narration","speaker":null,"text":{"KOREA":"최선이라는 명분으로 내가 너에게 어떤 희생을 강요했다면.","JPN":"最善という名目で私があなたに何らかの犠牲を押しつけたのなら。","ENG":"And while I forced you to make sacrifices in the name of having the best outcome.","TWN":"但我還是以最好的選擇為理由，強迫你做出了犧牲。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L12_1","type":"narration","speaker":null,"text":{"KOREA":"나는 반드시 그 책임을 져야만 한다고 말이야.","JPN":"私は必ずその責任を負うべきだわ。","ENG":"I must take responsibility for all of it.","TWN":"要對此負責的人，是我。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"반송장인 주제에 잘도 깡총깡총 뛰어다니네.","JPN":"死んでいるも同然のくせに、よくピョンピョンと飛びまわっていられるわね。","ENG":"For half a corpse, you seem to jump around pretty well.","TWN":"都快死了，話還這麼多。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"빙결 능력이라는 게 원래 이 정도까지 할 수 있는 거야?","JPN":"氷結能力って、元々こんなに使えるものなの？","ENG":"I didn't know freezing abilities could be this useful.","TWN":"凍結能力真的有這麼神奇？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"아니면 네가 환상종의 후예라서 그런 걸까?","JPN":"それとも、あなたが幻想種の末裔だからかしら。","ENG":"Or is it because you're a descendant of Bygones?","TWN":"還是因為你是夢幻品種的後裔？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"시끄러워……!!","JPN":"うるさい……！！","ENG":"Shut up...!!","TWN":"閉嘴……！！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L27_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"돌아올 곳이 있고, 널 기다리는 사람들이 있는데……. 네가 왜 길고양이겠어.","JPN":"帰る場所があって、あなたを待ってる人たちがいるのに……あなたが野良猫なわけないでしょ。","ENG":"You have a home, and people waiting for you to come back... You're not a stray cat.","TWN":"你有家可回，還有人在等你……你怎麼會是流浪貓呢？"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"넌 결국 훌륭하게 스스로 그림자를 끊어냈잖아?","JPN":"あなたは結局、自分で見事シャドウを断ち切ったじゃない。","ENG":"Plus, you defeated your own Shadow with excellence, no?","TWN":"最後，你自己成功斬斷了暗影吧？"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그러니 이제부터 넌 야크샤의 일원이자, 우리의 가족이야.","JPN":"だから、これからあなたはヤクシャーの一員で、私たちの家族よ。","ENG":"Now, you're a member of the Yaksha Division, and also our family.","TWN":"所以從現在開始，你不僅是夜叉的一員，也是我們這個大家庭的一員了。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"narration","speaker":null,"text":{"KOREA":"소중한 사람을 잃고, 텅 비어 버린 너의 마음을 채워 줄 수 있도록.","JPN":"大事な人を失って、空っぽになったあなたの心を満たしてあげるために。","ENG":"To fill your empty heart after losing someone dear to you.","TWN":"我願意成為你的朋友。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"narration","speaker":null,"text":{"KOREA":"내가 너의 친구가 되어주어야만 한다고.","JPN":"私があなたの友だちになる。","ENG":"I should become your friend.","TWN":"我願意成為你的家人。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"narration","speaker":null,"text":{"KOREA":"내가 너의 가족이 되어주어야만 한다고.","JPN":"私があなたの家族になるの。","ENG":"I should become your family.","TWN":"我願意去填補你那顆失去重要之人後，空虛的內心。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"쳇, 어딜 쏘는 거야? 네 상대는 카르멘이 아니라 나라고!!","JPN":"チッ、どこに撃ってるのかしら！　あなたの相手はカルメンではなくて私よ！","ENG":"Tsk, what are you even aiming at? You're fighting me, not Carmen!!","TWN":"嘖，你往哪裡瞄準呢？你的對手不是卡門，而是我！！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"이쪽을 보라고!! 끝까지 날 무시할 셈이야!?","JPN":"こっちを見なさい！！　私のことは最後まで眼中にないの！？","ENG":"Look over here!! Are you going to ignore me until you draw your last breath?!","TWN":"看這邊！！難道你要一直無視我嗎？！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"비켜……! 비키라고……!!","JPN":"どいて……！　どいてよ……！！","ENG":"Move...! I said, get out of my way...!!","TWN":"讓開……！叫你讓開……！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"나한테 너 같은 건, 아무래도 좋아!!","JPN":"あなたなんて、どうでもいい！！","ENG":"I don't care for the likes of you!!","TWN":"你算什麼東西！！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};